/* Test 10: End-to-end nominal sealed-pressure cycle */
static void test_end_to_end_cycle(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    printf("\n--- End-to-end cycle test ---\n");

    /* Boot: safe vent */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_NONE});
    printf("Boot: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Door closes */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_CLOSED});
    printf("Door closed: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Pressurize (low pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 35});
    printf("Low pressure (35): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Hold (medium pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 50});
    printf("Medium pressure (50): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Relieve (high pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 65});
    printf("High pressure (65): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Door opens - immediate safe vent */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_OPEN});
    printf("Door open: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    assert_equal_bool("End-to-end: Door open forces safe vent", output.vent_open);
}

int main(void)
{
    printf("\n=== Controller Tests ===\n\n");

    test_boot_safe_vent();
    test_initial_safe_vent_until_valid_sensors();
    test_low_pressure_pressurize();
    test_high_pressure_relieve();
    test_holding_band_preserves_output();
    test_door_open_forces_safe_vent();
    test_malformed_input_forces_safe_vent();
    test_never_compressor_and_vent_together();
    test_sensor_timeout_forces_safe_vent();
    test_end_to_end_cycle();

    printf("\n=== Results: %d/%d tests passed ===\n", tests_passed, tests_run);

    return (tests_passed == tests_run) ? TEST_PASS : TEST_FAIL;
}

