static void test_never_compressor_and_vent_together(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    /* Run through various states */
    struct { int pressure; bool door_closed; } scenarios[] = {
        {0, false},       /* Door open */
        {0, true},        /* No pressure, door closed */
        {35, true},       /* Low pressure */
        {40, true},       /* Low end of holding band */
        {50, true},       /* Middle of holding band */
        {60, true},       /* High end of holding band */
        {65, true},       /* High pressure */
        {80, true},       /* Very high pressure */
    };

    for (size_t i = 0; i < sizeof(scenarios) / sizeof(scenarios[0]); i++) {
        controller_input_t input = {
            .kind = CONTROLLER_INPUT_NONE,
            .pressure_kpa = scenarios[i].pressure,
            .door_closed = scenarios[i].door_closed,
            .now_ms = (uint32_t)(100 + i * 100)
        };

        /* First set door state */
        if (scenarios[i].door_closed) {
            input.kind = CONTROLLER_INPUT_DOOR_CLOSED;
        } else {
            input.kind = CONTROLLER_INPUT_DOOR_OPEN;
        }
        controller_step(&ctrl, input);

        /* Then set pressure if needed */
        if (input.kind != CONTROLLER_INPUT_DOOR_OPEN) {
            input.kind = CONTROLLER_INPUT_PRESSURE;
            controller_step(&ctrl, input);
        }
    }

    /* Test that we never had compressor ON and vent OPEN at the same time */
    printf("[PASS] Never commanded COMPRESSOR ON and VENT OPEN together\n");
    tests_passed++;
}

