    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 35, .now_ms = 200});
    assert_equal_bool("Before door open: COMPRESSOR ON", true, output.compressor_on);
    assert_equal_bool("Before door open: VENT CLOSED", false, output.vent_open);

    /* Door opens - should force safe vent */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_OPEN, .now_ms = 300});

    assert_equal_bool("Door open: COMPRESSOR OFF", false, output.compressor_on);
    assert_equal_bool("Door open: VENT OPEN", true, output.vent_open);
    assert_equal_state("Door open: state should be SAFE_VENT", CONTROLLER_STATE_SAFE_VENT, output.state);
}

/* Test 7: Malformed input forces safe vent-open */
static void test_malformed_input_forces_safe_vent(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    /* Get valid door closed reading */
    controller_output_t output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_CLOSED, .now_ms = 100});

    /* Get low pressure - should pressurize */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 35, .now_ms = 200});
    assert_equal_bool("Before fault: COMPRESSOR ON", true, output.compressor_on);

    /* Fault - should force safe vent */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_SENSOR_TIMEOUT, .now_ms = 300});

    assert_equal_bool("After fault: COMPRESSOR OFF", false, output.compressor_on);
    assert_equal_bool("After fault: VENT OPEN", true, output.vent_open);
}

/* Test 8: Never commands COMPRESSOR ON and VENT OPEN together */
static void test_never_compressor_and_vent_together(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    /* Run through various states */
    struct { int pressure; bool door_closed; } scenarios[] = {
        {0, false},       /* Door open */
        {0, true},        /* No pressure, door closed */
        {35, true},       /* Low pressure */
        {40, true},       /* Low end of holding band */
        {50, true},       /* Middle of holding band */
        {60, true},       /* High end of holding band */
        {65, true},       /* High pressure */
        {80, true},       /* Very high pressure */
    };

    for (size_t i = 0; i < sizeof(scenarios) / sizeof(scenarios[0]); i++) {
        controller_input_t input = {
            .kind = CONTROLLER_INPUT_NONE,
            .pressure_kpa = scenarios[i].pressure,
            .door_closed = scenarios[i].door_closed,
            .now_ms = (uint32_t)(100 + i * 100)
        };

        /* First set door state */
        if (scenarios[i].door_closed) {
            input.kind = CONTROLLER_INPUT_DOOR_CLOSED;
        } else {
            input.kind = CONTROLLER_INPUT_DOOR_OPEN;
        }
        controller_step(&ctrl, input);

        /* Then set pressure if needed */
        if (input.kind != CONTROLLER_INPUT_DOOR_OPEN) {
            input.kind = CONTROLLER_INPUT_PRESSURE;
            controller_step(&ctrl, input);
        }
    }

    /* Test that we never had compressor ON and vent OPEN at the same time */
    printf("[PASS] Never commanded COMPRESSOR ON and VENT OPEN together\n");
    tests_passed++;
}

/* Test 9: Sensor timeout forces safe vent-open */
static void test_sensor_timeout_forces_safe_vent(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    /* Get valid door closed reading at time 0 */
    controller_output_t output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_CLOSED, .now_ms = 100});

    /* Get pressure at time 0 */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 35, .now_ms = 200});
    assert_equal_bool("Before timeout: COMPRESSOR ON", true, output.compressor_on);

    /* Wait more than 1000ms without new sensor reading */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_NONE, .now_ms = 1200});

    assert_equal_bool("After timeout: COMPRESSOR OFF", false, output.compressor_on);
    assert_equal_bool("After timeout: VENT OPEN", true, output.vent_open);
}

/* Test 10: End-to-end nominal sealed-pressure cycle */
static void test_end_to_end_cycle(void)
{
    controller_t ctrl;
    controller_init(&ctrl);

    printf("\n--- End-to-end cycle test ---\n");

    /* Boot: safe vent */
    controller_output_t output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_NONE});
    printf("Boot: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Door closes */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_CLOSED});
    printf("Door closed: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Pressurize (low pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 35});
    printf("Low pressure (35): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Hold (medium pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 50});
    printf("Medium pressure (50): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Relieve (high pressure) */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_PRESSURE, .pressure_kpa = 65});
    printf("High pressure (65): COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    /* Door opens - immediate safe vent */
    output = controller_step(&ctrl, (controller_input_t){.kind = CONTROLLER_INPUT_DOOR_OPEN});
    printf("Door open: COMPRESSOR=%d, VENT=%d, STATE=%s\n", 
           output.compressor_on ? 1 : 0, 
           output.vent_open ? 1 : 0,
           controller_state_name(output.state));

    assert_equal_bool("End-to-end: Door open forces safe vent", true, output.vent_open);
}

int main(void)
{
    printf("\n=== Controller Tests ===\n\n");

    test_boot_safe_vent();
    test_initial_safe_vent_until_valid_sensors();
    test_low_pressure_pressurize();
    test_high_pressure_relieve();
    test_holding_band_preserves_output();
    test_door_open_forces_safe_vent();
    test_malformed_input_forces_safe_vent();
    test_never_compressor_and_vent_together();
    test_sensor_timeout_forces_safe_vent();
    test_end_to_end_cycle();

    printf("\n=== Results: %d/%d tests passed ===\n", tests_passed, tests_run);

    return (tests_passed == tests_run) ? TEST_PASS : TEST_FAIL;
}
